+        // Avoid unbounded growth: once we've consumed enough, shift the unread tail down.
+        let should_compact = self.position > 8 * 1024 || self.position > (self.buffer.len() / 2);
+        if should_compact {
+            self.buffer.drain(..self.position);
+            self.position = 0;
+        }
